mapper.select:
select * from wishlist
where user_id = #{userId}

    and status = #{status}

order by priority asc, created_at desc

mapper.update:
update wishlist
title = #{title}, description = #{description}, target_amount = #{targetAmount}, icon = #{icon}, color = #{color}, priority = #{priority}, target_date = #{targetDate}, updated_at = #{updatedAt}
where id = #{id}

update wishlist set current_amount = #{amount}, updated_at = now()
, status = #{status}
, completed_at = #{completedAt}
where id = #{id}
